91	func subprocessHarnessModelIDs(name string, cfg harnesses.HarnessConfig) []string {
92		models := append([]string(nil), cfg.Models...)
93		switch name {
94		case "claude":
95			runner := &claudeharness.Runner{}
96			snapshot := runner.DefaultModelSnapshot()
97			models = appendUniqueModelIDs(models, snapshot.Models...)
98			for _, family := range runner.SupportedAliases() {
99				if resolved, err := runner.ResolveModelAlias(family, snapshot); err == nil && resolved != family {
100					models = appendUniqueModelIDs(models, resolved)
101				}
102			}
103		case "codex":
104			snapshot := codexharness.DefaultCodexModelDiscovery()
105			models = appendUniqueModelIDs(models, snapshot.Models...)
106			for _, family := range []string{"gpt", "gpt-5"} {
107				resolved := codexharness.ResolveCodexModelAlias(family, snapshot)
108				if resolved != family {
109					models = appendUniqueModelIDs(models, resolved)
110				}
111			}
112		case "gemini":
113			mdh := &geminiharness.Runner{}
114			snapshot := mdh.DefaultModelSnapshot()
115			models = appendUniqueModelIDs(models, snapshot.Models...)
116			for _, family := range mdh.SupportedAliases() {
117				resolved, err := mdh.ResolveModelAlias(family, snapshot)
118				if err == nil && resolved != family {
119					models = appendUniqueModelIDs(models, resolved)
120				}
121			}
122		}
123		return models
124	}
