126	func resolveSubprocessModelAlias(harness, model string) string {
127		switch harness {
128		case "claude":
129			return claudeCLIExecutableModel(model)
130		case "codex":
131			return codexharness.ResolveCodexModelAlias(model, codexharness.DefaultCodexModelDiscovery())
132		case "gemini":
133			mdh := &geminiharness.Runner{}
134			resolved, err := mdh.ResolveModelAlias(model, mdh.DefaultModelSnapshot())
135			if err != nil {
136				return model
137			}
138			return resolved
139		default:
140			return model
141		}
142	}
