144	func claudeCLIExecutableModel(model string) string {
145		normalized := strings.ToLower(strings.TrimSpace(model))
146		switch {
147		case normalized == "sonnet" || strings.HasPrefix(normalized, "sonnet-") || strings.HasPrefix(normalized, "claude-sonnet-"):
148			return "sonnet"
149		case normalized == "opus" || strings.HasPrefix(normalized, "opus-") || strings.HasPrefix(normalized, "claude-opus-"):
150			return "opus"
151		case normalized == "haiku" || strings.HasPrefix(normalized, "haiku-") || strings.HasPrefix(normalized, "claude-haiku-"):
152			return "haiku"
153		default:
154			return model
155		}
156	}
157	
158	func appendUniqueModelIDs(values []string, additions ...string) []string {
159		for _, value := range additions {
160			value = strings.TrimSpace(value)
161			if value == "" {
162				continue
163			}
164			found := false
165			for _, existing := range values {
166				if existing == value {
167					found = true
168					break
169				}
170			}
171			if !found {
172				values = append(values, value)
173			}
174		}
175		return values
176	}
