178	func (s *service) listModelsFromSnapshot(ctx context.Context, sc ServiceConfig, cat *modelcatalog.Catalog, snapshot modelsnapshot.ModelSnapshot, filter ModelFilter) []ModelInfo {
179		defaultProviderName := sc.DefaultProviderName()
180		entries := make(map[string]ServiceProviderEntry, len(sc.ProviderNames()))
181		for _, name := range sc.ProviderNames() {
182			if filter.Provider != "" && filter.Provider != name {
183				continue
184			}
185			entry, ok := sc.Provider(name)
186			if !ok {
187				continue
188			}
189			entries[name] = entry
190		}
191	
192		modelsByProvider := make(map[string][]modelsnapshot.KnownModel, len(snapshot.Models))
193		for _, model := range snapshot.Models {
194			if filter.Provider != "" && filter.Provider != model.Provider {
195				continue
196			}
197			if _, ok := entries[model.Provider]; !ok {
198				continue
199			}
200			modelsByProvider[model.Provider] = append(modelsByProvider[model.Provider], model)
201		}
202	
203		rankByEndpoint := make(map[string]int, len(snapshot.Models))
204		out := make([]ModelInfo, 0, len(snapshot.Models))
205		for _, providerName := range sc.ProviderNames() {
206			if filter.Provider != "" && filter.Provider != providerName {
207				continue
208			}
209			entry, ok := entries[providerName]
210			if !ok {
211				continue
212			}
213			for _, model := range modelsByProvider[providerName] {
214				normalizedModel := model
215				normalizedModel.ServerInstance = serverinstance.Normalize(model.EndpointBaseURL, model.ServerInstance)
216				rankKey := strings.Join([]string{normalizedModel.Provider, normalizedModel.EndpointName, normalizedModel.EndpointBaseURL, normalizedModel.ServerInstance}, "\x00")
217				rank := rankByEndpoint[rankKey]
218				rankByEndpoint[rankKey] = rank + 1
219				out = append(out, s.modelInfoFromSnapshotModel(ctx, providerName, entry, defaultProviderName, cat, normalizedModel, rank))
220			}
221		}
222		return out
223	}
