225	func (s *service) modelInfoFromSnapshotModel(ctx context.Context, providerName string, entry ServiceProviderEntry, defaultProviderName string, cat *modelcatalog.Catalog, model modelsnapshot.KnownModel, rankPosition int) ModelInfo {
226		info := ModelInfo{
227			ID:              model.ID,
228			Provider:        providerName,
229			ProviderType:    model.ProviderType,
230			Harness:         model.Harness,
231			EndpointName:    model.EndpointName,
232			EndpointBaseURL: model.EndpointBaseURL,
233			ServerInstance:  model.ServerInstance,
234			ContextLength:   model.ContextWindow,
235			Utilization:     s.routeUtilizationEvidence(providerName, model.ServerInstance, model.EndpointName, model.ID),
236			Capabilities:    providerCapabilities(entry),
237			Cost: CostInfo{
238				InputPerMTok:  model.CostInputPerM,
239				OutputPerMTok: model.CostOutputPerM,
240			},
241			Power:                         model.Power,
242			AutoRoutable:                  model.AutoRoutable,
243			ExactPinOnly:                  model.ExactPinOnly,
244			Billing:                       model.Billing,
245			ActualCashSpend:               model.ActualCashSpend,
246			EffectiveCost:                 model.EffectiveCost,
247			EffectiveCostSource:           model.EffectiveCostSource,
248			SupportsTools:                 model.SupportsTools,
249			DeploymentClass:               model.DeploymentClass,
250			HealthFreshnessAt:             model.HealthFreshnessAt,
251			HealthFreshnessSource:         model.HealthFreshnessSource,
252			QuotaFreshnessAt:              model.QuotaFreshnessAt,
253			QuotaFreshnessSource:          model.QuotaFreshnessSource,
254			ModelDiscoveryFreshnessAt:     model.DiscoveredAt,
255			ModelDiscoveryFreshnessSource: string(model.DiscoveredVia),
256			Available:                     true,
257			RankPosition:                  rankPosition,
258		}
259		if info.Harness == "" {
260			info.Harness = "fiz"
261		}
262		info.ContextLength, info.ContextSource = resolveContextEvidence(ctx, entry, model.ID, cat)
263		if cat != nil {
264			_, info.PerfSignal = catalogCostAndPerf(cat, model.ID)
265		}
266		info.IsDefault = providerName == defaultProviderName && entry.Model != "" && model.ID == entry.Model
267		return info
268	}
