270	type modelDiscoveryEndpoint struct {
271		Name           string
272		BaseURL        string
273		ServerInstance string
274	}
275	
276	func modelDiscoveryEndpoints(entry ServiceProviderEntry) []modelDiscoveryEndpoint {
277		if len(entry.Endpoints) > 0 {
278			out := make([]modelDiscoveryEndpoint, 0, len(entry.Endpoints))
279			for _, ep := range entry.Endpoints {
280				if strings.TrimSpace(ep.BaseURL) == "" {
281					continue
282				}
283				out = append(out, modelDiscoveryEndpoint{
284					Name:           endpointDisplayName(ep.Name, ep.BaseURL),
285					BaseURL:        ep.BaseURL,
286					ServerInstance: serverinstance.Normalize(ep.BaseURL, ep.ServerInstance),
287				})
288			}
289			return out
290		}
291		if strings.TrimSpace(entry.BaseURL) == "" {
292			return nil
293		}
294		return []modelDiscoveryEndpoint{{
295			Name:           endpointDisplayName("default", entry.BaseURL),
296			BaseURL:        entry.BaseURL,
297			ServerInstance: serverinstance.Normalize(entry.BaseURL, entry.ServerInstance),
298		}}
299	}
300	
301	func endpointDisplayName(name, baseURL string) string {
302		if trimmed := strings.TrimSpace(name); trimmed != "" {
303			return trimmed
304		}
305		u, err := url.Parse(baseURL)
306		if err == nil && u.Host != "" {
307			return u.Host
308		}
309		return "default"
310	}
