312	// resolveContextEvidence resolves the context window for a model using the
313	// precedence chain: provider config > provider API > catalog > default.
314	func resolveContextEvidence(ctx context.Context, entry ServiceProviderEntry, modelID string, cat *modelcatalog.Catalog) (int, string) {
315		modelID = strings.TrimSpace(modelID)
316		if modelID == "" {
317			return 0, ContextSourceUnknown
318		}
319		if entry.ContextWindow > 0 {
320			return entry.ContextWindow, ContextSourceProviderConfig
321		}
322		if limits, source := providerAPIContextEvidence(ctx, entry, modelID); limits > 0 {
323			return limits, source
324		}
325		if cat != nil {
326			if n := cat.ContextWindowForModel(modelID); n > 0 {
327				return n, ContextSourceCatalog
328			}
329		}
330		return compaction.DefaultContextWindow, ContextSourceDefault
331	}
332	
333	func providerAPIContextEvidence(ctx context.Context, entry ServiceProviderEntry, modelID string) (int, string) {
334		switch entry.Type {
335		case "lmstudio":
336			if entry.BaseURL == "" {
337				return 0, ""
338			}
339			if limits := lmstudio.LookupModelLimits(ctx, entry.BaseURL, modelID); limits.ContextLength > 0 {
340				return limits.ContextLength, ContextSourceProviderAPI
341			}
342		case "omlx":
343			if entry.BaseURL == "" {
344				return 0, ""
345			}
346			if limits := omlx.LookupModelLimits(ctx, entry.BaseURL, modelID); limits.ContextLength > 0 {
347				return limits.ContextLength, ContextSourceProviderAPI
348			}
349		case "openrouter":
350			if entry.BaseURL == "" {
351				return 0, ""
352			}
353			if limits := openrouter.LookupModelLimits(ctx, entry.BaseURL, entry.APIKey, entry.Headers, modelID); limits.ContextLength > 0 {
354				return limits.ContextLength, ContextSourceProviderAPI
355			}
356		}
357		return 0, ""
358	}
