360	// catalogCostAndPerf extracts CostInfo and PerfSignal for a model from the catalog.
361	func catalogCostAndPerf(cat *modelcatalog.Catalog, modelID string) (CostInfo, PerfSignal) {
362		entry, ok := cat.LookupModel(modelID)
363		if !ok {
364			return CostInfo{}, PerfSignal{}
365		}
366		return CostInfo{
367				InputPerMTok:  catalogEntryInputCost(entry),
368				OutputPerMTok: catalogEntryOutputCost(entry),
369			}, PerfSignal{
370				SpeedTokensPerSec: entry.SpeedTokensPerSec,
371				SWEBenchVerified:  entry.SWEBenchVerified,
372			}
373	}
374	
375	func catalogPowerEligibility(cat *modelcatalog.Catalog, modelID string) (int, bool, bool) {
376		eligibility, ok := cat.ModelEligibility(modelID)
377		if !ok {
378			return 0, false, false
379		}
380		return eligibility.Power, eligibility.AutoRoutable, eligibility.ExactPinOnly
381	}
382	
383	// catalogPowerForModel returns the catalog-projected power for a model
384	// (CONTRACT-003 § Catalog Power Projection). Returns 0 when the catalog
385	// is nil or the model has no entry, which the contract documents as
386	// "unknown / exact-pin-only / no catalog entry" for the
387	// ServiceRoutingActual.Power surface.
388	func catalogPowerForModel(cat *modelcatalog.Catalog, modelID string) int {
389		if cat == nil || modelID == "" {
390			return 0
391		}
392		power, _, _ := catalogPowerEligibility(cat, modelID)
393		return power
394	}
395	
396	func catalogEntryInputCost(entry modelcatalog.ModelEntry) float64 {
397		if entry.CostInputPerM != 0 {
398			return entry.CostInputPerM
399		}
400		return entry.CostInputPerMTok
401	}
402	
403	func catalogEntryOutputCost(entry modelcatalog.ModelEntry) float64 {
404		if entry.CostOutputPerM != 0 {
405			return entry.CostOutputPerM
406		}
407		return entry.CostOutputPerMTok
408	}
409	
410	// providerCapabilities returns the capability set for a provider entry.
411	func providerCapabilities(entry ServiceProviderEntry) []string {
412		switch normalizeServiceProviderType(entry.Type) {
413		case "anthropic":
414			return []string{"tool_use", "vision", "streaming"}
415		case "omlx":
416			return []string{"tool_use", "streaming", "json_mode", "reasoning_control"}
417		default:
418			return []string{"tool_use", "streaming", "json_mode"}
419		}
420	}
