1	package fizeau
2	
3	import (
4		"context"
5		"time"
6	
7		"github.com/easel/fizeau/internal/harnesses"
8		claudeharness "github.com/easel/fizeau/internal/harnesses/claude"
9		codexharness "github.com/easel/fizeau/internal/harnesses/codex"
10		geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
11		"github.com/easel/fizeau/internal/routing"
12	)
13	
14	type subscriptionQuotaView struct {
15		OK          bool
16		Present     bool
17		Fresh       bool
18		Windows     []harnesses.QuotaWindow
19		PercentUsed int
20		Trend       string
21		Reason      string
22	}
23	
24	func subscriptionQuotaForHarness(name string, now time.Time) (subscriptionQuotaView, bool) {
25		switch name {
26		case "claude":
27			status, err := (&claudeharness.Runner{}).QuotaStatus(context.Background(), now)
28			if err != nil {
29				return subscriptionQuotaView{}, false
30			}
31			present := status.State != harnesses.QuotaUnavailable
32			view := subscriptionQuotaView{
33				OK:      status.RoutingPreference == harnesses.RoutingPreferenceAvailable,
34				Present: present,
35				Fresh:   status.Fresh,
36				Reason:  status.Reason,
37				Trend:   routing.QuotaTrendUnknown,
38			}
39			if present {
40				view.Windows = append([]harnesses.QuotaWindow(nil), status.Windows...)
41				view.PercentUsed = int(maxQuotaWindowUsedPercent(status.Windows))
42				view.Trend = quotaTrend(view.PercentUsed, status.Fresh)
43			}
44			return view, true
45		case "codex":
46			dec := codexharness.ReadCodexQuotaRoutingDecision(now, 0)
47			view := subscriptionQuotaView{
48				OK:      dec.PreferCodex,
49				Present: dec.SnapshotPresent,
50				Fresh:   dec.Fresh,
51				Reason:  dec.Reason,
52				Trend:   routing.QuotaTrendUnknown,
53			}
54			if dec.Snapshot != nil {
55				view.Windows = append([]harnesses.QuotaWindow(nil), dec.Snapshot.Windows...)
56				view.PercentUsed = int(maxQuotaWindowUsedPercent(dec.Snapshot.Windows))
57				view.Trend = quotaTrend(view.PercentUsed, dec.Fresh)
58			}
59			return view, true
60		case "gemini":
61			qh := &geminiharness.Runner{}
62			status, _ := qh.QuotaStatus(context.Background(), now)
63			view := subscriptionQuotaView{
64				OK:      status.RoutingPreference == harnesses.RoutingPreferenceAvailable,
65				Present: status.State != harnesses.QuotaUnavailable,
66				Fresh:   status.Fresh,
67				Reason:  status.Reason,
68				Trend:   routing.QuotaTrendUnknown,
69			}
70			if len(status.Windows) > 0 {
71				view.Windows = append([]harnesses.QuotaWindow(nil), status.Windows...)
72				view.PercentUsed = int(maxQuotaWindowUsedPercent(status.Windows))
73				exhausted, available := 0, 0
74				for _, w := range status.Windows {
75					switch w.State {
76					case "blocked":
77						exhausted++
78					case "ok":
79						available++
80					}
81				}
82				if exhausted > 0 && available == 0 {
83					view.Trend = routing.QuotaTrendExhausting
84				} else {
85					view.Trend = quotaTrend(view.PercentUsed, status.Fresh)
86				}
87			}
88			return view, true
89		default:
90			return subscriptionQuotaView{}, false
91		}
92	}
93	
94	func maxQuotaWindowUsedPercent(windows []harnesses.QuotaWindow) float64 {
95		maxUsed := 0.0
96		for _, window := range windows {
97			if window.UsedPercent > maxUsed {
98				maxUsed = window.UsedPercent
99			}
100		}
101		return maxUsed
102	}
103	
104	func quotaTrend(percentUsed int, fresh bool) string {
105		switch {
106		case percentUsed >= 90:
107			return routing.QuotaTrendExhausting
108		case percentUsed >= 70:
109			return routing.QuotaTrendBurning
110		case fresh:
111			return routing.QuotaTrendHealthy
112		default:
113			return routing.QuotaTrendUnknown
114		}
115	}
