208	func discoveryRecord(snapshot harnesses.ModelDiscoverySnapshot) cassette.DiscoveryRecord {
209		return cassette.DiscoveryRecord{
210			Source:            snapshot.Source,
211			Status:            string(ptyquota.StatusOK),
212			Models:            append([]string(nil), snapshot.Models...),
213			ReasoningLevels:   append([]string(nil), snapshot.ReasoningLevels...),
214			CapturedAt:        snapshot.CapturedAt.UTC().Format(time.RFC3339),
215			FreshnessWindow:   snapshot.FreshnessWindow,
216			StalenessBehavior: "stale model discovery evidence requires authenticated PTY refresh before capability promotion",
217			Metadata:          map[string]any{"detail": snapshot.Detail},
218		}
219	}
